Vue.use(Vuetify);
Vue.use(VueGrecaptcha);

const App = new Vue({
  el: '#form',
  delimiters: ['${', '}'],
  mounted() {
    const lightTheme = "light";
    const darkTheme = "dark";
    let initTheme = lightTheme;

    if ($("html[mode=dark]").length > 0 || ($("html[mode]").length == 0 && window.matchMedia("(prefers-color-scheme: dark)").matches)) {
      initTheme = darkTheme;
    }
    this.theme = initTheme;

    this.$vuetify.theme.dark = (initTheme !== 'dark') ? false : true;

    addEventListener('message', (event) => {
      if (event.source === window && event.data && event.data.direction === ModeToggle.ID) {
        const mode = event.data.message;

        this.$vuetify.theme.dark = (mode !== 'dark') ? false : true;
      }
    });
  },
  vuetify: new Vuetify(),
  data() {
    return {
      valid: true,
      contact: {
        name: '',
        email: '',
        message: ''
      },
      form: '',
      sitekey: '6LeZOAIeAAAAAPNCqN94M9BDK61TbRF52hFYRx88',
      captchaResponseCallback: '',
      theme: '',
      nameRules: [
        v => !!v || '이름은 필수 입니다.',
        v => v.length <= 10 || '10글자 이하로 입력해주세요.',
      ],
      emailRules: [
        v => !!v || '메일주소는 필수 입니다.',
        v => /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/.test(v) || '메일 주소 형식이 잘못되었습니다.',
      ],
      messageRules: [
        v => !!v || '내용은 필수 입니다.',
        v => v.length <= 200 || '200글자 이하로 입력해주세요.',
      ]
    }
  },
  methods: {
    validateBeforeSubmit: function () {
      if (this.$refs.contact.validate()) {
        grecaptcha.execute();
      }
    },
    resetRecaptcha: function () {
      grecaptcha.reset();
    },
    MailSubmit: function () {
      this.Emailsend();
      alert('준비중...');
    },
    /* Emailsend: function() {
      const xhr = new XMLHttpRequest();
      xhr.addEventListener('load', function (_ref) {
        var target = _ref.target;
      });
      xhr.addEventListener('error', function (_ref2) {
        var target = _ref2.target;
        console.log(target);
      });
      xhr.open('GET', 'https://api.boolean.kr/', true);
      xhr.send(this.contact);
    } */
  }
});

